#include<bits/stdc++.h>
#define Accepted UnAccepted
#define inf 0x3f3f3f3f
#define mod 998244353
#define ll long long
#define M 500010
#define N 100010
#define quickly ios::sync_with_stdio(0);cin.tie(0);cout.tie(0)
using namespace std;
ll t,m,a,b,c,po[505];
int main(){
	quickly;
	for(int i=1;i<=500;i++)
		po[i]=i*i;
	cin >>t>>m;
	while(t--){
		cin >>a>>b>>c;
		if(a<=0){
			a=-a;
			b=-b;
			c=-c;
		}
		if(b==0 && c==0){
			cout<<0<<endl;
		}
		else if(c==0){
			if(a*b>0){
				cout<<'0'<<endl;
			}else {
				c=__gcd(abs(2*a),abs(b));
				b=b/c;
				a=(2*a)/c;
				if(a==1) cout<<-b<<endl;
				else cout<<-b<<'/'<<a<<endl;
			}
		}
		else if(b*b-4*a*c<0){
			cout<<"NO"<<endl;
			continue;
		}else if(b*b==4*a*c){
			c=__gcd(abs(2*a),abs(b));
			b=b/c;
			a=(2*a)/c;
			if(a==1) cout<<-b<<endl;
			else cout<<-b<<'/'<<a<<endl;
		}else {
			ll p=1,v=b*b-4*a*c,a_1=a,b_1=b,c_1;
			for(int i=500;i>=2;i--){
				while(v%po[i]==0){
					v=v/po[i];
					p*=i;
				}
			}
			if(v==1){
				b=-b+p;
				c=__gcd(abs(b),a+a);
				b/=c;
				a=(a+a)/c;
				if(a==1) cout<<b<<endl;
				else cout<<b<<'/'<<a<<endl;
			}else {
				c=__gcd(2*a_1,abs(b));
				b=b/c;
				a_1=(2*a_1)/c;
				if(b!=0){
					if(a_1==1) cout<<-b;
					else cout<<-b<<'/'<<a_1;
					cout<<'+';
				}
				c=__gcd(2*a,p);
				p=p/c;
				a=(2*a)/c;
				if(a==1){ 
					if(p!=1)
						cout<<p<<"*sqrt("<<v<<')'<<endl;
					else 
						cout<<"sqrt("<<v<<')'<<endl;
				}
				else{
					if(p!=1)
						cout<<p<<"*sqrt("<<v<<')'<<'/'<<a<<endl;
					else 
						cout<<"sqrt("<<v<<')'<<'/'<<a<<endl;
				}
			}
		}
	}

	return 0;
}
